import {
  FieldGroup
} from "@/components/ui/field"
import { FormProvider, useForm, type UseFormPropsExtended, } from '@airiot/client'
import React, { type ReactNode } from 'react'
import { zodResolver } from "@hookform/resolvers/zod"
import { Resolver } from 'react-hook-form'
import { z } from 'zod'
import get from 'lodash/get'
import {
  convertToSchemaFormRules,
} from '@/registry/lib/field-rules-hooks'
import type { FieldRules } from '@/registry/lib/field-rules-hooks'
import { evaluateValidations, evaluateConditions } from '@/registry/lib/field-rules-engine'

// 全局设置 Zod 中文错误提示
z.config({
  localeError: (issue) => {
    switch (issue.code) {
      case 'too_small':
        if (issue.origin === 'string') return '不能为空'
        if (issue.origin === 'array') return '请至少添加一条数据'
        return '值太小'
      case 'too_big':
        if (issue.origin === 'string') return '内容过长'
        if (issue.origin === 'array') return '超出最大数量'
        return '值太大'
      case 'invalid_type':
        if (issue.expected === 'string') return '请填写此项'
        if (issue.expected === 'number') return '请填写数字'
        return '请填写此项'
      case 'invalid_value':
        return '请选择有效的选项'
      default:
        return '请检查填写内容'
    }
  }
})

import { FormField } from "@/registry/components/form-field/form-field"
import { formConverter } from '@/registry/lib/view-form-converter'
import { getControlValidate } from '@/registry/lib/form-field-validate'

import type { ModelSchema, FormSchemaItem } from '@/registry/lib/model-types'

type SchemaFormProps = UseFormPropsExtended & {
  formId: string
  schema: ModelSchema,
  formSchema: FormSchemaItem[],
  schameConvert?: (schema: any, field: object) => void,
  onSubmit?: (data: any) => void
  isValid?: boolean
  showDescribe?: boolean
  children?: ReactNode | ((props: any) => ReactNode)
  classNames?: Record<'form' | 'group' | 'field' | 'label' | 'input' | 'description' | 'error', string> & { groupStyle?: React.CSSProperties }
  fieldRules?: FieldRules
}

const SchemaForm = ({ schema, formSchema, onSubmit, formId, children, showDescribe = true, isValid = true, classNames, schameConvert, onEffect, fieldRules, ...props }: SchemaFormProps) => {
  // 字段规则转换
  const schemaFieldRules = React.useMemo(() =>
    fieldRules ? convertToSchemaFormRules(fieldRules) : undefined,
    [fieldRules]
  )

  // 跟踪动态必填字段（由规则引擎设置）
  const dynamicRequiredRef = React.useRef<Set<string>>(new Set())
  const rulesPrevValuesRef = React.useRef<Record<string, any>>({})

  // 包装 onEffect：在调用原始 onEffect 前更新动态必填
  const wrappedOnEffect = React.useCallback((values: any, methods: any) => {
    if (schemaFieldRules?.rules?.length) {
      dynamicRequiredRef.current.clear()
      const changedFields = new Set(
        Object.keys(values).filter(k => values[k] !== rulesPrevValuesRef.current[k])
      )
      for (const rule of schemaFieldRules.rules) {
        if (rule.disabled) continue
        const triggerFields = new Set(rule.when.flat().map(c => c.field))
        if (triggerFields.size > 0 && ![...triggerFields].some(f => changedFields.has(f))) continue
        const matched = evaluateConditions(rule.when, values, rulesPrevValuesRef.current)
        const effects = matched ? rule.then : rule.else
        effects?.forEach((effect: any) => {
          if (effect.type === 'require' && effect.field) {
            const targets = Array.isArray(effect.field) ? effect.field : [effect.field]
            targets.forEach((f: string) => dynamicRequiredRef.current.add(f))
          }
        })
      }
      rulesPrevValuesRef.current = { ...values }
    }
    onEffect?.(values, methods)
  }, [onEffect, schemaFieldRules])
  // 处理 formSchema，展开 '*' 通配符
  const processedFormSchema = React.useMemo(() => {
    const allPropertyKeys = Object.keys(schema?.properties || {})
    const result: Array<{ key: string, controlType?: string, [key: string]: any }> = []
    const explicitKeys = new Set<string>()

    for (const item of formSchema || []) {
      if (item === '*') {
        // 展开通配符：添加所有未显式指定的字段
        const remainingKeys = allPropertyKeys.filter(key => !explicitKeys.has(key))
        for (const key of remainingKeys) {
          result.push({ key })
        }
      } else {
        // 普通字段项
        result.push(item)
        explicitKeys.add(item.key)
      }
    }

    return result
  }, [schema, formSchema])

  // 预处理 schema：当 type=array 且顶层有 enum 时，将 enum 移入 items
  const preprocessSchema = React.useCallback((schema: any): any => {
    if (!schema?.properties) return schema
    const processed = { ...schema, properties: { ...schema.properties } }
    const requiredKeys: string[] = []
    for (const [key, prop] of Object.entries(processed.properties) as [string, any][]) {
      // need/required → JSON Schema 标准约束
      if (prop?.need || prop?.required) {
        requiredKeys.push(key)
        if (prop?.type === 'string' && prop?.minLength === undefined) {
          processed.properties[key] = { ...prop, minLength: 1 }
        }
        if (prop?.type === 'array' && prop?.minItems === undefined) {
          processed.properties[key] = { ...processed.properties[key], minItems: 1 }
        }
      }
      // enum 从数组顶层移入 items
      if (prop?.type === 'array' && prop?.enum) {
        const { enum: _, ...rest } = processed.properties[key]
        processed.properties[key] = {
          ...rest,
          items: {
            ...(prop.items || {}),
            enum: prop.enum,
          },
        }
      }
    }
    if (requiredKeys.length > 0) {
      processed.required = [...(processed.required || []), ...requiredKeys]
    }
    return processed
  }, [])

  const zodSchema = React.useMemo(() => {
    try {
      return z.fromJSONSchema(preprocessSchema(schema) as any)
    } catch (e) {
      console.error('Failed to convert schema to Zod:', e)
      return z.object({})
    }
  }, [schema, preprocessSchema])

  const getMergedSchema = (schema: any, field: string | Record<string, any>) => {
    const fieldKey = typeof field === 'string' ? field : field.key
    const fieldSchema = typeof field === 'string' ? { key: field } : field
    const _fieldKey = fieldKey.includes('.') ? fieldKey.replace('.', '.properties.') : fieldKey
    const baseSchema = get(schema, `properties.${_fieldKey}`)

    // 如果 FormSchemaItem 中有 required 属性，将其转换为 need
    let merged = { ...baseSchema, ...fieldSchema }
    if (typeof field === 'object' && field.required) {
      merged = { ...merged, need: true }
    }

    return { fieldKey, mergedSchema: merged }
  }

  const resolver = React.useMemo<Resolver<any, any>>(() => {
    const zodResolverFn = zodResolver(zodSchema as any)
    return async (values, context, options) => {
      const zodResult = await zodResolverFn(values, context, options)
      // 始终跑 controlType 校验，合并错误
      for (const field of processedFormSchema) {
          const { fieldKey, mergedSchema } = getMergedSchema(schema, field)
          const controlValidate = getControlValidate(mergedSchema)
          if (controlValidate) {
            const error = await controlValidate(values[fieldKey])
            if (error) {
              ;(zodResult.errors as Record<string, unknown>)[fieldKey] = { type: 'validate', message: error }
            }
          }
        }
      // 动态必填（由字段规则 setRequire 设置）
      for (const field of dynamicRequiredRef.current) {
        if (values[field] == null || values[field] === '') {
          ;(zodResult.errors as Record<string, unknown>)[field] = { type: 'required', message: '此字段为必填项' }
        }
      }
      // 字段规则校验（正则 pattern）
      if (schemaFieldRules?.validations?.length) {
        const valErrors = evaluateValidations(schemaFieldRules.validations, values)
        for (const [field, error] of Object.entries(valErrors)) {
          ;(zodResult.errors as Record<string, unknown>)[field] = error
        }
      }
      return zodResult
    }
  }, [zodSchema, processedFormSchema, schema, schemaFieldRules])

  // 从 schema 中提取默认值，与 props.defaultValues 合并（props 优先）
  const schemaDefaults = React.useMemo(() => {
    if (!schema?.properties) return {}
    const defaults: Record<string, unknown> = {}
    for (const [key, prop] of Object.entries(schema.properties) as [string, Record<string, unknown>][]) {
      if (prop?.defaultVal !== undefined) {
        defaults[key] = prop.defaultVal
      }
    }
    return defaults
  }, [schema])

  const methods = useForm({
    resolver: isValid ? resolver : null,
    onEffect: wrappedOnEffect,
    defaultValues: isValid ? { ...schemaDefaults, ...props.defaultValues } : {},
    ...props
  } as any)

  // 在表单挂载后手动调用一次 onEffect，用于初始化字段可见性等
  const hasCalledInitOnEffect = React.useRef(false)

  React.useEffect(() => {
    if (onEffect && schema && !hasCalledInitOnEffect.current) {
      // 获取当前表单的默认值
      const defaultValues = methods.getValues()
      onEffect(defaultValues, methods)
      hasCalledInitOnEffect.current = true
    }
  }, [schema])

  const handleFormSubmit = async (data: any) => {
    onSubmit?.(data)
  }

  return (
    <FormProvider {...methods} classNames={classNames}>
      <form id={formId} noValidate onSubmit={methods.handleSubmit(handleFormSubmit)} className={classNames?.form}>
        <FieldGroup className={classNames?.group} style={classNames?.groupStyle}>
          {processedFormSchema.map(field => {
            const { fieldKey, mergedSchema } = getMergedSchema(schema, field)
            const FieldController = (
              typeof field !== 'string' && field.component
                ? field.component
                : schameConvert
                  ? schameConvert(mergedSchema, field)
                  : formConverter(mergedSchema, field)
            ) as React.ComponentType
            return (
              <FormField name={fieldKey} label={mergedSchema?.title} schema={mergedSchema} required={isValid ? mergedSchema?.need : false} showDescribe={showDescribe}>
                <FieldController />
              </FormField>
            )
          })}
        </FieldGroup>
        {
          children ? (typeof children === 'function' ? children({
            ...methods
          }) : children) : null
        }
      </form>
    </FormProvider>
  )
}

export { SchemaForm }

/**
 * 字段规则 Hook
 *
 * 提供 onEffect 回调和 resolver 包装，用于集成到 SchemaForm
 */

import { useCallback, useMemo, useRef } from 'react'
import type { Resolver, FieldValues } from 'react-hook-form'
import {
  type SchemaFormFieldRules,
  type SchemaFormRule,
  type UseFormReturnExtended,
  applyRules,
  evaluateValidations,
  evaluateConditions,
} from './field-rules-engine'

// ============================================================================
// 编辑器格式类型（用于 convertToSchemaFormRules）
// ============================================================================

/** 编辑器触发条件项 */
export interface ConditionItem {
  field: string
  method: string
  value?: any
}

/** 编辑器交互动作类型 */
export type MutualActionType = 'show' | 'hide' | 'setRequire' | 'setOptional' | 'canEdit' | 'setDisabled' | 'setValue' | 'message'

/** 编辑器交互动作 */
export interface MutualAction {
  type: MutualActionType
  field?: string | string[]
  value?: any
}

/** 编辑器交互规则 */
export interface MutualRule {
  name: string
  key: string
  condition: ConditionItem[][]
  action: MutualAction[]
  disabled?: boolean
}

/** 编辑器字段校验 */
export interface FieldValidation {
  id: string
  field: string
  pattern: string
  message: string
  disabled?: boolean
}

/** 编辑器字段规则（顶层结构） */
export interface FieldRules {
  mutualRules?: MutualRule[]
  validations?: FieldValidation[]
}

// ============================================================================
// 转换：编辑器格式 → 标准格式
// ============================================================================

const ACTION_TYPE_MAP: Record<string, SchemaFormRule['then'][number]['type']> = {
  show: 'show',
  hide: 'hide',
  setRequire: 'require',
  setOptional: 'optional',
  setValue: 'setValue',
  message: 'message',
  canEdit: 'enable',
  setDisabled: 'disable',
}

/**
 * 编辑器 FieldRules → 标准 SchemaFormFieldRules
 */
export function convertToSchemaFormRules(rules: FieldRules): SchemaFormFieldRules {
  return {
    rules: (rules.mutualRules || [])
      .filter(r => !r.disabled)
      .map(rule => ({
        when: (rule.condition || []).map(group =>
          group.map(cond => ({
            field: cond.field,
            op: (cond.method || 'eq') as SchemaFormRule['when'][number][number]['op'],
            value: cond.value,
          }))
        ),
        then: (rule.action || [])
          .map(a => ({
            type: ACTION_TYPE_MAP[a.type] || a.type,
            field: a.field,
            value: a.value,
          })),
      })) as SchemaFormRule[],
    validations: (rules.validations || [])
      .filter(v => !v.disabled && v.field && v.pattern)
      .map(v => ({
        field: v.field,
        pattern: v.pattern,
        message: v.message,
      })),
  }
}

// ============================================================================
// Hook: onEffect 回调
// ============================================================================

/**
 * 创建处理交互规则的 onEffect 回调
 *
 * 防重入策略：setValue 前比较值，相同则跳过 → 自然终止递归，无需时序守卫。
 */
export function useFieldRulesEffect(fieldRules: SchemaFormFieldRules | undefined, schema?: Record<string, any>) {
  const prevValuesRef = useRef<Record<string, any>>({})
  const applyingRef = useRef(false)

  const onEffect = useCallback(
    (values: FieldValues, methods: UseFormReturnExtended) => {
      if (!fieldRules?.rules?.length && !fieldRules?.validations?.length) return
      if (applyingRef.current) return
      applyingRef.current = true
      try {
        if (fieldRules.rules?.length) {
          const changedFields = new Set(
            Object.keys(values).filter(k => values[k] !== prevValuesRef.current[k])
          )
          for (const rule of fieldRules.rules) {
            if (rule.disabled) continue
            const triggerFields = new Set(rule.when.flat().map(c => c.field))
            if (triggerFields.size > 0 && ![...triggerFields].some(f => changedFields.has(f))) continue
            const matched = evaluateConditions(rule.when, values as Record<string, any>, prevValuesRef.current)
            const effects = matched ? rule.then : rule.else
            effects?.forEach(effect => {
              if (effect.type === 'message' && effect.value && !effect.field) {
                console.warn('[FieldRules message]', effect.value)
              }
            })
          }
          applyRules(fieldRules.rules, values as Record<string, any>, prevValuesRef.current, methods, schema)
        }
        if (fieldRules.validations?.length) {
          const errors = evaluateValidations(fieldRules.validations, values as Record<string, any>)
          for (const [field, error] of Object.entries(errors)) {
            methods.setError(field, error)
          }
          for (const v of fieldRules.validations) {
            if (v.field && !errors[v.field]) {
              const currentError = (methods.formState as any)?.errors?.[v.field]
              if (currentError?.type === 'validate') {
                methods.clearErrors(v.field)
              }
            }
          }
        }
      } finally {
        prevValuesRef.current = { ...methods.getValues() as Record<string, any> }
        applyingRef.current = false
      }
    },
    [fieldRules, schema],
  )

  return onEffect
}

// ============================================================================
// Hook: resolver 包装
// ============================================================================

/**
 * 包装 resolver，叠加字段校验
 */
export function useFieldRulesResolver(
  baseResolver: Resolver<any, any> | undefined,
  fieldRules: SchemaFormFieldRules | undefined,
): Resolver<any, any> | undefined {
  const validations = fieldRules?.validations

  return useMemo(() => {
    if (!baseResolver || !validations?.length) return baseResolver

    return async (values, context, options) => {
      const result = await baseResolver(values, context, options)

      const errors = evaluateValidations(validations, values as Record<string, any>)
      for (const [field, error] of Object.entries(errors)) {
        ;(result.errors as Record<string, unknown>)[field] = error
      }

      return result
    }
  }, [baseResolver, validations])
}

/**
 * 字段规则引擎
 *
 * 标准数据结构 + 条件匹配 + 效果执行
 * 供 SchemaForm 消费，通过 onEffect 和 resolver 集成
 */

/** 扩展的表单方法（由 @airiot/client 的 useForm 提供） */
export interface UseFormReturnExtended {
  getValues(): Record<string, any>
  setValue(name: string, value: any): void
  setError(name: string, error: { type: string; message: string }): void
  clearErrors(name?: string): void
  setFieldUIState?: (name: string, state: Record<string, any>) => void
  formState?: { errors?: Record<string, { type: string; message: string } | undefined> }
}

// ============================================================================
// 标准类型定义（SchemaForm 消费的通用格式）
// ============================================================================

/** SchemaForm 标准字段规则 */
export interface SchemaFormFieldRules {
  /** 条件规则：满足条件 → 执行效果 */
  rules?: SchemaFormRule[]
  /** 字段校验 */
  validations?: SchemaFormValidation[]
}

/** 单条规则 */
export interface SchemaFormRule {
  /** 触发条件：外层 OR，内层 AND */
  when: SchemaFormCondition[][]
  /** 条件满足时执行 */
  then: SchemaFormEffect[]
  /** 条件不满足时执行（可选，用于反向逻辑） */
  else?: SchemaFormEffect[]
  disabled?: boolean
}

/** 条件项 */
export interface SchemaFormCondition {
  field: string
  op: 'eq' | 'ne' | 'gt' | 'lt' | 'ge' | 'le' | 'in' | 'nin' | 'isNull' | 'notNull' | 'contains' | 'onchange'
  value?: any
}

/** 效果项 */
export interface SchemaFormEffect {
  type: 'show' | 'hide' | 'require' | 'optional' | 'setValue' | 'message' | 'disable' | 'enable'
  field: string | string[]
  value?: any
}

/** 字段校验 */
export interface SchemaFormValidation {
  field: string
  pattern: string
  message: string
}

// ============================================================================
// 条件匹配
// ============================================================================

function matchCondition(cond: SchemaFormCondition, values: Record<string, any>, prevValues: Record<string, any>): boolean {
  const actual = values[cond.field]

  switch (cond.op) {
    case 'eq':      return Array.isArray(cond.value) ? cond.value.includes(actual) : actual == cond.value
    case 'ne':      return Array.isArray(cond.value) ? !cond.value.includes(actual) : actual != cond.value
    case 'gt':      return Number(actual) > Number(cond.value)
    case 'lt':      return Number(actual) < Number(cond.value)
    case 'ge':      return Number(actual) >= Number(cond.value)
    case 'le':      return Number(actual) <= Number(cond.value)
    case 'in':      return Array.isArray(cond.value) && cond.value.includes(actual)
    case 'nin':     return Array.isArray(cond.value) && !cond.value.includes(actual)
    case 'isNull':  return actual == null || actual === ''
    case 'notNull': return actual != null && actual !== ''
    case 'contains': return String(actual ?? '').includes(String(cond.value ?? ''))
    case 'onchange': return actual !== prevValues[cond.field]
    default:        return true
  }
}

/**
 * 评估条件组（外层 OR，内层 AND）
 */
export function evaluateConditions(
  groups: SchemaFormCondition[][],
  values: Record<string, any>,
  prevValues: Record<string, any>,
): boolean {
  if (!groups?.length) return true
  return groups.some(group =>
    group.every(cond => matchCondition(cond, values, prevValues))
  )
}

// ============================================================================
// 效果执行
// ============================================================================

function coerceValue(value: any, fieldType?: string): any {
  if (value == null) return value
  if (fieldType === 'number' || fieldType === 'int' || fieldType === 'double') {
    const n = Number(value)
    return isNaN(n) ? value : n
  }
  if (fieldType === 'boolean') {
    if (value === 'true') return true
    if (value === 'false') return false
    return Boolean(value)
  }
  return value
}

/**
 * 解析模板值，支持 {{fieldName}} 占位符
 *
 * 示例：
 *   "{{a}} + {{b}}"     → 数值运算: a=1, b=2 → 3
 *   "{{a}} * {{b}}"     → 数值运算: a=10, b=3 → 30
 *   "{{a}}{{b}}"         → 字符串拼接: a="hello", b="world" → "helloworld"
 *   "前缀-{{a}}-后缀"    → 混合: a=1 → "前缀-1-后缀"
 *   "{{a}}"              → 简单引用: a=222 → "222"
 */
function resolveEffectValue(template: any, values: Record<string, any>): any {
  if (typeof template !== 'string' || !template.includes('{{')) {
    return template
  }

  const resolved = template.replace(/\{\{([^}]+)\}\}/g, (_, fieldPath) => {
    const path = fieldPath.trim()
    const val = path.split('.').reduce((obj: any, key: string) => obj?.[key], values)
    return val == null ? '' : String(val)
  })

  const trimmed = resolved.trim()
  if (/[\+\-\*\/]/.test(trimmed) && /^[\d\s+\-*/().]+$/.test(trimmed)) {
    try {
      return new Function(`return (${trimmed})`)()
    } catch {
      return resolved
    }
  }

  return resolved
}

function applyEffect(
  effect: SchemaFormEffect,
  methods: UseFormReturnExtended,
  _values: Record<string, any>,
  schema?: Record<string, any>,
) {
  const targets = Array.isArray(effect.field) ? effect.field : effect.field ? [effect.field] : []
  const setUI = methods.setFieldUIState

  switch (effect.type) {
    case 'show':
      targets.forEach(f => setUI?.(f, { visible: true }))
      break
    case 'hide':
      targets.forEach(f => setUI?.(f, { visible: false }))
      break
    case 'require':
      targets.forEach(f => setUI?.(f, { required: true }))
      break
    case 'optional':
      targets.forEach(f => setUI?.(f, { required: false }))
      break
    case 'disable':
      targets.forEach(f => setUI?.(f, { disabled: true }))
      break
    case 'enable':
      targets.forEach(f => setUI?.(f, { disabled: false }))
      break
    case 'setValue':
      targets.forEach(f => {
        if (effect.value !== undefined) {
          const resolvedValue = resolveEffectValue(effect.value, methods.getValues())
          const currentValue = methods.getValues()[f]
          const fieldType = schema?.properties?.[f]?.type as string | undefined
          const newValue = coerceValue(resolvedValue, fieldType)
          if (currentValue !== newValue) {
            methods.setValue(f, newValue)
          }
        }
      })
      break
    case 'message':
      if (effect.value) {
        if (targets.length > 0) {
          targets.forEach(f => methods.setError(f, { type: 'message', message: String(effect.value) }))
        }
      }
      break
  }
}

/**
 * 应用所有规则
 *
 * 只在触发字段（条件中的字段）发生变化时才求值规则，
 * 避免用户修改目标字段时被规则强行覆盖。
 */
export function applyRules(
  rules: SchemaFormRule[],
  values: Record<string, any>,
  prevValues: Record<string, any>,
  methods: UseFormReturnExtended,
  schema?: Record<string, any>,
) {
  const changedFields = new Set(
    Object.keys(values).filter(k => values[k] !== prevValues[k])
  )

  for (const rule of rules) {
    if (rule.disabled) continue

    const triggerFields = new Set(rule.when.flat().map(c => c.field))

    if (triggerFields.size > 0 && ![...triggerFields].some(f => changedFields.has(f))) {
      continue
    }

    const matched = evaluateConditions(rule.when, values, prevValues)
    const effects = matched ? rule.then : rule.else
    effects?.forEach(effect => applyEffect(effect, methods, values, schema))
  }
}

// ============================================================================
// 校验执行
// ============================================================================

/**
 * 执行字段校验，返回错误映射
 */
export function evaluateValidations(
  validations: SchemaFormValidation[],
  values: Record<string, any>,
): Record<string, { type: string; message: string }> {
  const errors: Record<string, { type: string; message: string }> = {}

  for (const v of validations) {
    if (!v.field || !v.pattern) continue
    const actual = values[v.field]
    if (actual == null || actual === '') continue
    try {
      if (!new RegExp(v.pattern).test(String(actual))) {
        errors[v.field] = { type: 'validate', message: v.message || '格式不正确' }
      }
    } catch {
      // 无效正则，跳过
    }
  }

  return errors
}

import type { FieldProperty } from '@/registry/lib/model-types'

/**
 * 字段校验函数
 * 返回 undefined 表示校验通过，返回字符串表示错误信息
 */
export type FieldValidateFn = (value: unknown) => string | undefined | Promise<string | undefined>

/**
 * 根据 schema 生成校验函数
 */
export type ValidateFactory = (schema: FieldProperty) => FieldValidateFn | undefined

/**
 * controlType → 校验工厂映射
 */
const controlsValidate: Record<string, ValidateFactory> = {
  'editable-table': (schema) => {
    const items = schema?.items

    const hasEditableTableForms = items?.formSchema && items?.properties

    if (!hasEditableTableForms) return undefined

    const requiredFields: Array<{ key: string; title: string }> = []
    items.formSchema.forEach(({ key }: { key: string }) => {
      const fieldSchema = items.properties[key]
      if (fieldSchema?.need === true) {
        requiredFields.push({
          key: fieldSchema.key || key,
          title: fieldSchema.title || key
        })
      }
    })

    if (requiredFields.length === 0) return undefined

    return (value: unknown) => {
      const rows = value as unknown[]
      if (!Array.isArray(rows) || rows.length === 0) {
        return `请至少添加一条数据`
      }
      for (let i = 0; i < rows.length; i++) {
        const row = rows[i] as Record<string, unknown>
        for (const field of requiredFields) {
          const fieldValue = row?.[field.key]
          if (fieldValue === null || fieldValue === undefined || fieldValue === '') {
            return `第 ${i + 1} 行的「${field.title}」不能为空`
          }
        }
      }
      return undefined
    }
  },
}

/**
 * 根据 schema.controlType 获取校验函数
 */
export function getControlValidate(schema: FieldProperty): FieldValidateFn | undefined {
  const controlType = schema?.controlType
  if (!controlType) return undefined
  const factory = controlsValidate[controlType]
  if (!factory) return undefined
  return factory(schema)
}

export { controlsValidate }
